/* 
  Algorithm: Greedy simulation with a single current charm's HP.
  Key idea: fight whenever curHP >= next enemy; otherwise charm.
*/
#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    if (!(cin >> n)) return 0;
    vector<int> hp(n);
    for (int i = 0; i < n; i++) {
        cin >> hp[i];
    }

    int charms = 0;
    int curHP = 0;
    int i = 0;
    while (i < n) {
        if (curHP == 0) {
            // Must charm the next enemy to start fighting
            curHP = hp[i++];
            charms++;
        } else {
            if (curHP >= hp[i]) {
                // Fight and kill the enemy
                curHP -= hp[i++];
            } else {
                // Our charm would die; better to charm this enemy first
                curHP = hp[i++];
                charms++;
            }
        }
    }

    cout << charms << "\n";
    return 0;
}
